  "select",
  "input[type=\"range\"]",
  "input[type=\"button\"]",
  "input[type=\"checkbox\"]",
  "input[type=\"radio\"]",
  "input[type=\"reset\"]",
  "input[type=\"submit\"]",
  "[role=\"button\"]",
  ".cursor-pointer",
  "[data-cursor=\"active\"]",
  "[data-cursor=\"pointer\"]",
].join(", ");

export function getPressedCursorState(target: EventTarget | null) {
  if (typeof Element === "undefined" || !(target instanceof Element)) {
    return null;
  }

  if (target.closest(disabledCursorSelector)) {
    return null;
  }

  const panningElement = target.closest(panningCursorSelector);
  const activeElement = target.closest(activeCursorSelector);

  if (
    panningElement &&
    (!activeElement ||
      panningElement === activeElement ||
      activeElement.contains(panningElement))
  ) {
    return "grabbing";
  }

  if (activeElement) {
    return "active";
  }

  return null;
}

import {
  getSwirskiCursor,
  swirskiCursors,
  type CursorId,
  type SwirskiCursor,
} from "./cursors";

export function getStoredCursor(
  storageKey: string | false,
  cursors: SwirskiCursor[],
): CursorId | null {
  if (storageKey === false || typeof window === "undefined") {
    return null;
  }

  try {
    const storedCursor = window.localStorage.getItem(storageKey);

    if (!storedCursor) {
      return null;
    }

    const exists = cursors.some((cursor) => cursor.id === storedCursor);

    return exists ? (storedCursor as CursorId) : null;
  } catch {
    return null;
  }
}

export function storeCursor(storageKey: string | false, cursorId: CursorId) {
  if (storageKey === false || typeof window === "undefined") {
    return;
  }

  try {
    window.localStorage.setItem(storageKey, cursorId);
  } catch {
    // Ignore storage errors, for example private browsing or blocked storage.
  }
}

export function findCursor(cursors: SwirskiCursor[], cursorId: CursorId) {
  return (
    cursors.find((cursor) => cursor.id === cursorId) ??
    getSwirskiCursor(cursorId) ??
    cursors[0] ??
    swirskiCursors[0]
  );
}

