export type NavbarDropdownTriggerProps =
  ButtonHTMLAttributes<HTMLButtonElement> & {
    active?: boolean;
    asChild?: boolean;
    variant?: NavbarVariant;
    size?: NavbarSize;
    tone?: NavbarTone;
  };

export const NavbarDropdownTrigger = forwardRef<
  HTMLButtonElement,
  NavbarDropdownTriggerProps
>(function NavbarDropdownTrigger(
  {
    active = false,
    asChild = false,
    children,
    className,
    variant = "default",
    size = "md",
    tone = "default",
    onClick,
    onKeyDown,
    ...props
  },
  ref,
) {
  const { contentId, focusIntentRef, open, setOpen, triggerRef } =
    useDropdownMenu();
  const Component = asChild ? Slot : "button";

  return (
    <Component
      ref={composeRefs(triggerRef, ref)}
      className={cn(
        navbarLinkStyles({ active, variant }),
        "cursor-pointer gap-2",
        className,
      )}
      onClick={(event) => {
        onClick?.(event);

        if (!event.defaultPrevented) {
          setOpen(!open);
        }
      }}
      onKeyDown={(event) => {
        onKeyDown?.(event);

        if (event.defaultPrevented) {
          return;
        }

        if (
          event.key === "ArrowDown" ||
          event.key === "Enter" ||
          event.key === " "
        ) {
          event.preventDefault();
          focusIntentRef.current = "first";
          setOpen(true);
          return;
        }

        if (event.key === "ArrowUp") {
          event.preventDefault();
          focusIntentRef.current = "last";
          setOpen(true);
        }
      }}
      type={asChild ? undefined : "button"}
      aria-controls={open ? contentId : undefined}
      aria-expanded={open}
      aria-haspopup="menu"
      {...swirskiAttrs("navbar-dropdown-trigger", { size, tone, variant })}
      data-active={active ? "" : undefined}
      {...props}
    >
      {asChild ? (
        children
      ) : (
        <>
          {children}
          <span
            aria-hidden="true"
            className="h-0 w-0 border-x-[4px] border-t-[5px] border-x-transparent border-t-current"
          />
        </>
      )}
    </Component>
  );
});

