import { Dispatch, SetStateAction, useCallback, useState } from "react";

export type UseControllableStateProps<T> = {
  value?: T;
  defaultValue: T;
  onChange?: (value: T) => void;
};

export function useControllableState<T>({
  value,
  defaultValue,
  onChange,
}: UseControllableStateProps<T>): [T, Dispatch<SetStateAction<T>>] {
  const [internalValue, setInternalValue] = useState(defaultValue);
  const isControlled = value !== undefined;
  const currentValue = isControlled ? value : internalValue;

  const setValue = useCallback<Dispatch<SetStateAction<T>>>(
    (nextValue) => {
      const resolvedValue =
        typeof nextValue === "function"
          ? (nextValue as (currentValue: T) => T)(currentValue as T)
          : nextValue;

      if (!isControlled) {
        setInternalValue(resolvedValue);
      }

      onChange?.(resolvedValue);
    },
    [currentValue, isControlled, onChange],
  );

  return [currentValue as T, setValue];
}

"use client";

import { useCallback } from "react";
import { useControllableState } from "../use-controllable-state";

export type UseDisclosureHandlers = {
  open: () => void;
  close: () => void;
  toggle: () => void;
  set: (opened: boolean) => void;
};

export type UseDisclosureOptions = {
  value?: boolean;
  onChange?: (opened: boolean) => void;
};

export function useDisclosure(
  defaultOpened = false,
  options: UseDisclosureOptions = {},
): [boolean, UseDisclosureHandlers] {
  const [opened, setOpened] = useControllableState({
    value: options.value,
    defaultValue: defaultOpened,
    onChange: options.onChange,
  });

  const open = useCallback(() => setOpened(true), [setOpened]);
  const close = useCallback(() => setOpened(false), [setOpened]);
  const toggle = useCallback(
    () => setOpened((currentOpened) => !currentOpened),
    [setOpened],
  );

  return [opened, { open, close, toggle, set: setOpened }];
}

"use client";

import { useEffect } from "react";

export type UseEscapeKeyOptions = {
  enabled?: boolean;
  target?: Document | HTMLElement | Window | null;
};

export function useEscapeKey(
  handler: (event: KeyboardEvent) => void,
  options: UseEscapeKeyOptions = {},
) {
  const { enabled = true, target } = options;

  useEffect(() => {
    if (!enabled) {
      return;
    }

    const eventTarget = target ?? document;

    const listener = (event: Event) => {
      const keyboardEvent = event as KeyboardEvent;

      if (keyboardEvent.key === "Escape") {
        handler(keyboardEvent);
      }
    };

    eventTarget.addEventListener("keydown", listener);

    return () => eventTarget.removeEventListener("keydown", listener);
  }, [enabled, handler, target]);
}

export {
  isPathnameActive,
  useIsPathnameActive,
} from "./useIsPathnameActive";
export type {
  IsPathnameActiveOptions,
  PathnameUrl,
} from "./useIsPathnameActive";

import { describe, expect, it } from "vitest";
import { isPathnameActive } from "./useIsPathnameActive";

describe("isPathnameActive", () => {
  it("matches exact and nested paths", () => {
    expect(isPathnameActive("/components", "/components")).toBe(true);
    expect(isPathnameActive("/components", "/components/button")).toBe(true);
    expect(isPathnameActive("/components", "/components-button")).toBe(false);
  });

  it("supports exact matching", () => {
    expect(
      isPathnameActive("/components", "/components/button", { exact: true }),
    ).toBe(false);
  });

  it("normalizes URLs, query strings, and trailing slashes", () => {
    expect(
      isPathnameActive(
        "/components/",
        "https://swirski.dev/components/button?tab=props",
      ),
    ).toBe(true);
  });

  it("only marks the root path active for the root URL", () => {
    expect(isPathnameActive("/", "/")).toBe(true);
    expect(isPathnameActive("/", "/components")).toBe(false);
  });
});

"use client";

import { useMemo } from "react";

export type IsPathnameActiveOptions = {
  exact?: boolean;
};

export type PathnameUrl = string | URL;

const URL_BASE = "https://swirski.local";

function toPathname(value: PathnameUrl) {
  if (value instanceof URL) {
    return normalizePathname(value.pathname);
  }

  return normalizePathname(new URL(value, URL_BASE).pathname);
}

function normalizePathname(pathname: string) {
  const normalizedPathname = pathname.startsWith("/")
    ? pathname
    : `/${pathname}`;

  if (normalizedPathname === "/") {
    return normalizedPathname;
  }

  return normalizedPathname.replace(/\/+$/, "");
}

export function isPathnameActive(
  pathname: PathnameUrl,
  currentUrl: PathnameUrl,
  { exact = false }: IsPathnameActiveOptions = {},
) {
  const targetPathname = toPathname(pathname);
  const currentPathname = toPathname(currentUrl);

  if (exact || targetPathname === "/") {
    return currentPathname === targetPathname;
  }

  return (
    currentPathname === targetPathname ||
    currentPathname.startsWith(`${targetPathname}/`)
  );
}

export function useIsPathnameActive(
  pathname: PathnameUrl,
  currentUrl: PathnameUrl,
  { exact = false }: IsPathnameActiveOptions = {},
) {
  return useMemo(
    () => isPathnameActive(pathname, currentUrl, { exact }),
    [currentUrl, exact, pathname],
  );
}

"use client";

import { Dispatch, SetStateAction, useEffect, useState } from "react";

export type UseLocalStorageOptions<T> = {
  serialize?: (value: T) => string;
  deserialize?: (value: string) => T;
};

export function useLocalStorage<T>(
  key: string,
  defaultValue: T,
  options: UseLocalStorageOptions<T> = {},
): [T, Dispatch<SetStateAction<T>>, () => void] {
  const serialize = options.serialize ?? JSON.stringify;
  const deserialize = options.deserialize ?? JSON.parse;
  const [value, setValue] = useState(defaultValue);

  useEffect(() => {
    try {
      const storedValue = window.localStorage.getItem(key);

      if (storedValue !== null) {
        setValue(deserialize(storedValue));
      }
    } catch {
      setValue(defaultValue);
    }
  }, [defaultValue, deserialize, key]);

  useEffect(() => {
    try {
      window.localStorage.setItem(key, serialize(value));
    } catch {
      // Ignore storage failures in private browsing and restricted contexts.
    }
  }, [key, serialize, value]);

  function removeValue() {
    try {
      window.localStorage.removeItem(key);
    } finally {
      setValue(defaultValue);
    }
  }

  return [value, setValue, removeValue];
}

"use client";

import { useEffect, useState } from "react";

export function useMediaQuery(query: string, initialValue = false) {
  const [matches, setMatches] = useState(initialValue);

  useEffect(() => {
    const mediaQuery = window.matchMedia(query);

    setMatches(mediaQuery.matches);

    const listener = (event: MediaQueryListEvent) => {
      setMatches(event.matches);
    };

    mediaQuery.addEventListener("change", listener);

    return () => mediaQuery.removeEventListener("change", listener);
  }, [query]);

  return matches;
}

"use client";

import { useEffect, useState } from "react";

export function usePortalRoot() {
  const [portalRoot, setPortalRoot] = useState<HTMLElement | null>(null);

  useEffect(() => {
    setPortalRoot(document.body);
  }, []);

  return portalRoot;
}

"use client";

import { useMediaQuery } from "../use-media-query";

export function useReducedMotion(initialValue = false) {
  return useMediaQuery("(prefers-reduced-motion: reduce)", initialValue);
}
